/**
 * Seed the production Betti artifact registry (Wave D4 registry provisioning).
 *
 * HONESTY RULE: no fake rows. Every emitted row derives from a REAL
 * `.wasm` module carrying its `gnosis-betti-manifest` custom section, and the
 * pair is integrity-verified (`validateBettiWasmArtifactPair`: manifest
 * sha256 over bytes[..byteLength]) BEFORE anything is staged. A module that
 * fails to parse or verify aborts the run.
 *
 * This script performs NO network writes itself — it stages the exact
 * objects + SQL and prints the wrangler commands (resource seeding is a
 * deliberate operator/agent CLI step, mirroring the world-knots
 * `wrangler r2 object put` convention):
 *
 *   pnpm run gnode -- run open-source/gnosis/scripts/seed-betti-registry.ts \
 *     --wasm <module.wasm> [--wasm ...] --out-dir <staging> \
 *     [--owner-did <did>] [--price-cents <n>]
 *
 * Output: <staging>/betti/v1/<artifactId>.{wasm,manifest.json} (the exact R2
 * key layout), <staging>/seed.sql (CREATE TABLE IF NOT EXISTS + guarded
 * ADD COLUMNs + INSERT OR REPLACE rows), and a command list on stdout.
 */
import { readFile, mkdir, writeFile } from 'node:fs/promises';
import { basename, dirname, join, resolve } from 'node:path';
import {
  parseBettiManifestCustomSection,
} from '../src/betti-wasm-manifest';
import {
  BETTI_WASM_ARTIFACTS_TABLE,
  bettiWasmManifestKey,
  bettiWasmModuleKey,
  validateBettiWasmArtifactPair,
} from '../src/betti-wasm-store';
import { fragmentKey } from '../src/polyglot-vfs';

interface Args {
  wasmFiles: string[];
  outDir: string;
  ownerDid: string | null;
  priceCents: number | null;
  bucket: string;
  database: string;
}

function parseArgs(argv: string[]): Args {
  const wasmFiles: string[] = [];
  let outDir: string | undefined;
  let ownerDid: string | null = null;
  let priceCents: number | null = null;
  let bucket = 'betti-registry';
  let database = 'betti-registry';
  for (let index = 0; index < argv.length; index += 1) {
    const flag = argv[index];
    const value = argv[index + 1];
    if (flag === '--wasm' && value) {
      wasmFiles.push(resolve(value));
      index += 1;
    } else if (flag === '--out-dir' && value) {
      outDir = resolve(value);
      index += 1;
    } else if (flag === '--owner-did' && value) {
      ownerDid = value;
      index += 1;
    } else if (flag === '--price-cents' && value) {
      priceCents = Math.max(0, Math.round(Number(value)));
      index += 1;
    } else if (flag === '--bucket' && value) {
      bucket = value;
      index += 1;
    } else if (flag === '--database' && value) {
      database = value;
      index += 1;
    } else {
      throw new Error(`unknown flag '${flag}'`);
    }
  }
  if (wasmFiles.length === 0 || !outDir) {
    throw new Error(
      'usage: seed-betti-registry.ts --wasm <file> [--wasm ...] --out-dir <dir> [--owner-did <did>] [--price-cents <n>] [--bucket <name>] [--database <name>]'
    );
  }
  return { wasmFiles, outDir, ownerDid, priceCents, bucket, database };
}

function sqlText(value: string): string {
  return `'${value.replace(/'/g, "''")}'`;
}

function sqlValue(value: string | number | null): string {
  if (value === null) {
    return 'NULL';
  }
  return typeof value === 'number' ? String(value) : sqlText(value);
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv.slice(2));
  const createdAt = new Date().toISOString();

  const ddl = [
    `CREATE TABLE IF NOT EXISTS ${BETTI_WASM_ARTIFACTS_TABLE} (
  artifact_id TEXT PRIMARY KEY,
  key TEXT NOT NULL,
  file_path TEXT NOT NULL,
  function_name TEXT NOT NULL,
  language TEXT NOT NULL,
  tier TEXT NOT NULL,
  pure INTEGER NOT NULL,
  manifest_json TEXT NOT NULL,
  r2_key TEXT,
  byte_length INTEGER NOT NULL,
  sha256 TEXT NOT NULL,
  created_at TEXT NOT NULL,
  owner_did TEXT,
  price_cents INTEGER
);`,
    `CREATE INDEX IF NOT EXISTS idx_betti_wasm_artifacts_key ON ${BETTI_WASM_ARTIFACTS_TABLE}(key);`,
  ];

  const inserts: string[] = [];
  const uploads: string[] = [];
  const summaries: Record<string, unknown>[] = [];

  for (const wasmPath of args.wasmFiles) {
    const wasmBytes = new Uint8Array(await readFile(wasmPath));
    const manifest = parseBettiManifestCustomSection(wasmBytes);
    if (manifest === null) {
      throw new Error(
        `${basename(wasmPath)}: no gnosis-betti-manifest custom section — not a betti-wasm/1 artifact, refusing to seed`
      );
    }
    const manifestJson = `${JSON.stringify(manifest, null, 2)}\n`;
    // Integrity gate — throws on any tamper/truncation. No fake rows.
    await validateBettiWasmArtifactPair(wasmBytes, manifestJson);

    const moduleKey = bettiWasmModuleKey(manifest.artifactId);
    const manifestKey = bettiWasmManifestKey(manifest.artifactId);
    const stagedModule = join(args.outDir, moduleKey);
    const stagedManifest = join(args.outDir, manifestKey);
    await mkdir(dirname(stagedModule), { recursive: true });
    await writeFile(stagedModule, wasmBytes);
    await writeFile(stagedManifest, manifestJson, 'utf8');

    inserts.push(
      `INSERT OR REPLACE INTO ${BETTI_WASM_ARTIFACTS_TABLE}
  (artifact_id, key, file_path, function_name, language, tier, pure, manifest_json, r2_key, byte_length, sha256, created_at, owner_did, price_cents)
VALUES (${[
        sqlValue(manifest.artifactId),
        sqlValue(fragmentKey(manifest.filePath, manifest.functionName)),
        sqlValue(manifest.filePath),
        sqlValue(manifest.functionName),
        sqlValue(manifest.language),
        sqlValue(manifest.tier),
        manifest.pure ? 1 : 0,
        sqlValue(manifestJson),
        sqlValue(moduleKey),
        manifest.byteLength,
        sqlValue(manifest.sha256),
        sqlValue(createdAt),
        sqlValue(args.ownerDid),
        sqlValue(args.priceCents),
      ].join(', ')});`
    );
    uploads.push(
      `npx wrangler r2 object put ${args.bucket}/${moduleKey} --file ${stagedModule} --remote`,
      `npx wrangler r2 object put ${args.bucket}/${manifestKey} --file ${stagedManifest} --remote`
    );
    summaries.push({
      artifactId: manifest.artifactId,
      tier: manifest.tier,
      certifiedClass: manifest.certified_class,
      pure: manifest.pure,
      language: manifest.language,
      functionName: manifest.functionName,
      topologyHash: manifest.topologyHash,
      sourceHash: manifest.sourceHash,
      sha256: manifest.sha256,
      byteLength: manifest.byteLength,
      ownerDid: args.ownerDid,
      priceCents: args.priceCents,
      integrity: 'verified',
    });
  }

  const seedSqlPath = join(args.outDir, 'seed.sql');
  await writeFile(
    seedSqlPath,
    `${[...ddl, ...inserts].join('\n\n')}\n`,
    'utf8'
  );

  process.stdout.write(
    `${JSON.stringify({ artifacts: summaries, seedSql: seedSqlPath }, null, 2)}\n`
  );
  process.stdout.write('\n# Run to publish (D1 rows + R2 object pairs):\n');
  process.stdout.write(
    `npx wrangler d1 execute ${args.database} --remote --file ${seedSqlPath} -y\n`
  );
  for (const command of uploads) {
    process.stdout.write(`${command}\n`);
  }
}

main().catch((error) => {
  process.stderr.write(
    `seed-betti-registry: ${error instanceof Error ? error.message : String(error)}\n`
  );
  process.exit(1);
});
